import{c as a,Q as t,j as s,m as n}from"./chunks/framework.DYp_ty9j.js";const g=JSON.parse('{"title":"Kong Gateway Operator","description":"","frontmatter":{},"headers":[],"relativePath":"showcases/kong-gateway-operator.md","filePath":"showcases/kong-gateway-operator.md","lastUpdated":1775743342000}'),o={name:"showcases/kong-gateway-operator.md"};function i(r,e,l,p,h,c){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="kong-gateway-operator" tabindex="-1">Kong Gateway Operator <a class="header-anchor" href="#kong-gateway-operator" aria-label="Permalink to &quot;Kong Gateway Operator&quot;">​</a></h1><h3 id="precondition" tabindex="-1">Precondition <a class="header-anchor" href="#precondition" aria-label="Permalink to &quot;Precondition&quot;">​</a></h3><p>Cluster has to be deployed with the <em>HAProxy Ingress Controller</em> and the <em>HTTPBin example</em>. <strong>DNS preparation</strong></p><p>You can test Kong Ingress by adding the following entry to your <em>/etc/hosts</em> file:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Append to /etc/hosts</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[...]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">127.0.0.1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">		httpbin.example.com</span></span></code></pre></div><h3 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h3><p>You can start the installation of the Kong Gateway Operator with the included shell script:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/kong-gateway-operator</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup.sh</span></span></code></pre></div><p>The following components are installed with the <em>setup.sh</em>:</p><ul><li>Installs OpenBao for certificate management (from <code>examples/openbao</code>) <ul><li>Installs cert-manager HELM Chart</li><li>Creates a wildcard certificate for domain <em>example.com</em> - used for Kong Gateway</li></ul></li><li>Installs Gateway API CRDs</li><li>Enables Kubernetes Gateway API support for cert-manager</li><li>Installs Kong Gateway Operator instance using Kong Operator HELM Chart (to namespace <em>kong-system</em>) - <a href="https://github.com/Kong/charts/tree/main/charts/gateway-operator" target="_blank" rel="noreferrer">https://github.com/Kong/charts/tree/main/charts/gateway-operator</a></li><li>Configures Kong Gateway instance <ul><li>Creates Namespace Kong</li><li>Creates GatewayClass, GatewayConfiguration and Gateway resources</li><li>After that Kong Gateway is available in the namespace <em>kong</em> and can be called with the URL: <a href="https://localhost:8081" target="_blank" rel="noreferrer">https://localhost:8081</a></li></ul></li><li>Creates HTTPRoute resource for the HTTPBin example <ul><li>After that you can open <em>httpbin</em> with the URL: <a href="https://httpbin.example.com:8081/httpbin-api/v1/anything" target="_blank" rel="noreferrer">https://httpbin.example.com:8081/httpbin-api/v1/anything</a></li></ul></li></ul><blockquote><p><strong>NOTE</strong></p><p>When you have added the Root CA to your system Truststore, or your browser the connection should be secured correctly. You can find the Root CA certificate under: <code>examples/openbao/root-certs/rootCACert.pem</code>.</p></blockquote>`,11)])])}const m=a(o,[["render",i]]);export{g as __pageData,m as default};
